\\STATE $C[A[j]] = C[A[j]] + 1$
\\ENDFOR
\\FOR{$i = 1$ to $k$}
\\STATE $C[i] = C[i] + C[i-1]$
\\ENDFOR
\\FOR{$j = A.length$ downto $1$}
\\STATE $B[C[A[j]]] = A[j]$
\\STATE $C[A[j]] = C[A[j]] - 1$
\\ENDFOR
\\end{algorithmic}
\\end{algorithm}

Figure 8.2 illustrates counting sort. After the \\texttt{for} loop of lines 2--3 initializes the array $C$ to all zeros, the \\texttt{for} loop of lines 4--5 inspects each input element. If the value of an input element is $i$, we increment $C[i]$. Thus, after line 5, $C[i]$ holds the number of input elements equal to $i$ for each integer $i = 0, 1, \\ldots, k$. Lines 7--8 determine for each $i = 0, 1, \\ldots, k$ how many input elements are less than or equal to $i$ by keeping a running sum of the array $C$.

\\section{8.4 Bucket sort}
\\label{sec:bucket-sort}

\\begin{figure}[htbp]
\\centering
\\includegraphics[width=0.8\\textwidth]{_page_0_Figure_1.jpeg}
\\caption{The operation of BUCKET-SORT for $n = 10$. (a) The input array $A[1..10]$. (b) The array $B[0..9]$ of sorted lists (buckets) after line 8 of the algorithm. Bucket $i$ holds values in the half-open interval $[i/10, (i+1)/10)$. The sorted output consists of a concatenation in order of the lists $B[0], B[1], \\ldots, B[9]$.}
\\label{fig:bucket-sort}
\\end{figure}

\\begin{algorithm}
\\caption{BUCKET-SORT($A$)}
\\begin{algorithmic}[1]
\\STATE $n = A.length$
\\STATE let $B[0..n-1]$ be a new array
\\FOR{$i = 0$ to $n - 1$}
\\STATE make $B[i]$ an empty list
\\ENDFOR
\\FOR{$i = 1$ to $n$}
\\STATE insert $A[i]$ into list $B[\\lfloor nA[i] \\rfloor]$
\\ENDFOR
\\FOR{$i = 0$ to $n - 1$}
\\STATE sort list $B[i]$ with insertion sort
\\ENDFOR
\\STATE concatenate the lists $B[0], B[1], \\ldots, B[n-1]$ together in order
\\end{algorithmic}
\\end{algorithm}

Figure~\\ref{fig:bucket-sort} shows the operation of bucket sort on an input array of 10 numbers.

To see that this algorithm works, consider two elements $A[i]$ and $A[j]$. Assume without loss of generality that $A[i] \\leq A[j]$. Since $\\lfloor nA[i] \\rfloor \\leq \\lfloor nA[j] \\rfloor$, either element $A[i]$ goes into the same bucket as $A[j]$ or it goes into a bucket with a lower index. If $A[i]$ and $A[j]$ go into the same bucket, then the \\textbf{for} loop of lines 7--8 puts them into the proper order. If $A[i]$ and $A[j]$ go into different buckets, then line 9 puts them into the proper order. Therefore, bucket sort works correctly.

To analyze the running time, observe that all lines except line 8 take $O(n)$ time in the worst case. We need to analyze the total time taken by the $n$ calls to insertion sort in line 8.

\\section{8.4 Bucket sort}
\\begin{align*}
\\mathrm{E}\\left[n_{i}^{2}\\right] &= \\mathrm{E}\\left[\\left(\\sum_{j=1}^{n} X_{ij}\\right)^{2}\\right] \\\\
&= \\mathrm{E}\\left[\\sum_{j=1}^{n} \\sum_{k=1}^{n} X_{ij} X_{ik}\\right] \\\\
&= \\mathrm{E}\\left[\\sum_{j=1}^{n} X_{ij}^{2} + \\sum_{1 \\leq j \\leq n} \\sum_{\\substack{1 \\leq k \\leq n \\\\ k \\neq j}} X_{ij} X_{ik}\\right] \\\\
&= \\sum_{j=1}^{n} \\mathrm{E}\\left[X_{ij}^{2}\\right] + \\sum_{1 \\leq j \\leq n} \\sum_{\\substack{1 \\leq k \\leq n \\\\ k \\neq j}} \\mathrm{E}\\left[X_{ij} X_{ik}\\right], \\qquad (8.3)
\\end{align*}
where the last line follows by linearity of expectation. We evaluate the two summations separately. Indicator random variable $X_{ij}$ is 1 with probability $1/n$ and 0 otherwise, and therefore
\\begin{align*}
\\mathrm{E}\\left[X_{ij}^{2}\\right] &= 1^{2} \\cdot \\frac{1}{n} + 0^{2} \\cdot \\left(1 - \\frac{1}{n}\\right) \\\\
&= \\frac{1}{n}.
\\end{align*}
When $k \\neq j$, the variables $X_{ij}$ and $X_{ik}$ are independent, and hence
\\begin{align*}
\\mathrm{E}\\left[X_{ij} X_{ik}\\right] &= \\mathrm{E}\\left[X_{ij}\\right] \\mathrm{E}\\left[X_{ik}\\right] \\\\
&= \\frac{1}{n} \\cdot \\frac{1}{n} \\\\
&= \\frac{1}{n^{2}}.
\\end{align*}
Substituting these two expected values in equation (8.3), we obtain
\\begin{align*}
\\mathrm{E}\\left[n_{i}^{2}\\right] &= \\sum_{j=1}^{n} \\frac{1}{n} + \\sum_{1 \\leq j \\leq n} \\sum_{\\substack{1 \\leq k \\leq n \\\\ k \\neq j}} \\frac{1}{n^{2}} \\\\
&= n \\cdot \\frac{1}{n} + n(n-1) \\cdot \\frac{1}{n^{2}} \\\\
&= 1 + \\frac{n-1}{n} \\\\
&= 2 - \\frac{1}{n},
\\end{align*}
which proves equation (8.2).

\\section{9.3 Selection in worst-case linear time}

