\\STATE $x = L.nil.next$
\\WHILE{$x \\neq L.nil$ and $x.key \\neq k$}
\\STATE $x = x.next$
\\ENDWHILE
\\RETURN $x$
\\end{algorithmic}
\\end{algorithm}

