\\begin{algorithm}[htbp]
\\caption{B-TREE-INSERT-NONFULL($x, k$)}
\\begin{algorithmic}[1]
\\STATE $i = x.n$
\\IF{$x.\\text{leaf}$}
\\WHILE{$i \\ge 1$ and $k < x.\\text{key}_i$}
\\STATE $x.\\text{key}_{i+1} = x.\\text{key}_i$
\\STATE $i = i - 1$
\\ENDWHILE
\\STATE $x.\\text{key}_{i+1} = k$
\\STATE $x.n = x.n + 1$
\\STATE \\textsc{DISK-WRITE}(x)
\\ELSE
\\WHILE{$i \\ge 1$ and $k < x.\\text{key}_i$}
\\STATE $i = i - 1$
\\ENDWHILE
\\STATE $i = i + 1$
\\STATE \\textsc{DISK-READ}(x.c_i)
\\IF{$x.c_i.n == 2t - 1$}
\\STATE \\textsc{B-TREE-SPLIT-CHILD}(x, i)
\\ENDIF
\\IF{$k > x.\\text{key}_i$}
\\STATE $i = i + 1$
\\ENDIF
\\STATE \\textsc{B-TREE-INSERT-NONFULL}(x.c_i, k)
\\ENDIF
\\end{algorithmic}
\\end{algorithm}

